                },
            },
        ]);

        const { result } = renderHook(() => {
            const [chats, setChats] = useState<Chat[]>([createInitialChat()]);
            const chatGenerator = useChatGenerator({
                chats,
                setChats,
                selectedModel: 'model-a',
                selectedProvider: 'antigravity',
